 // Node: "Prepare AI Context" — Mode: Run Once for All Items
// Purpose: Assemble complete context for AI agent including history and lead state
// Version: Web Chat (uses Normalize Web Payload instead of Normalize WABA Payload)

const waba = $('Normalize Web Payload').first().json || {};

// === GET SESSION ROW ===
let row = {};
try {
  const lookup = $('Lookup Lead Session').first().json;
  if (lookup && lookup.session_id) row = lookup;
} catch(e) {}
try {
  if (!row.session_id) {
    const created = $('Create Lead Session').first().json;
    if (created && created.session_id) row = created;
  }
} catch(e) {}

// === LEAD STATE ===
const state = {
  name:                    row.name                    || waba.name || null,
  email:                   row.email                   || waba.email || null,
  email_valid:             row.email_valid              || false,
  phone_number:            row.phone_number             || waba.phone_number || null,
  platform:                row.platform                 || null,
  communication_channels:  row.communication_channels   || [],
  main_customer_questions: row.main_customer_questions  || [],
  message_volume:          row.message_volume           || null,
  friction_area:           row.friction_area            || null,
  signals:                 row.signals                  || [],
  temperature:             row.temperature              || "cold",
  next_action:             row.next_action              || "continue",
  pending_field:           row.pending_field            || null,
  pending_question:        row.pending_question         || null,
  country:                 row.country                  || null,
  available_slots:         row.available_slots          || [],
  selected_slot:           row.selected_slot            || null,
  summary:                 row.summary                  || ""
};

// === CONVERSATION HISTORY ===
let history = [];
try {
  let raw_history = row.conversation_history;
  if (typeof raw_history === 'string') raw_history = JSON.parse(raw_history);
  if (raw_history && typeof raw_history === 'object' && !Array.isArray(raw_history)) {
    raw_history = raw_history.data || raw_history.value || [];
  }
  if (Array.isArray(raw_history)) history = raw_history;
  else history = [];
} catch(e) {
  history = [];
}

const recentHistory = history.slice(-20);
const historyText = recentHistory.length > 0
  ? recentHistory.map(function(h) {
      return (h.role === 'user' ? 'Usuario' : 'Andrea') + ': ' + h.content;
    }).join('\n')
  : "Primera interaccion con este usuario.";

// === LEAD STATE AS NATURAL LANGUAGE ===
const lines = [];
lines.push("- Nombre: "           + (state.name          || 'No capturado'));
lines.push("- Email: "            + (state.email
  ? state.email + (state.email_valid ? ' (verificado)' : ' (sin verificar)')
  : 'No capturado'));
lines.push("- Telefono: "         + (state.phone_number   || 'No capturado'));
if (state.country) lines.push("- Pais: " + state.country);
lines.push("- Plataforma: "       + (state.platform       || 'No capturada'));
lines.push("- Volumen mensajes: " + (state.message_volume || 'No capturado'));
lines.push("- Canales: "          + (
  state.communication_channels && state.communication_channels.length > 0
    ? state.communication_channels.join(', ')
    : 'No capturados'
));
lines.push("- Friccion: "         + (state.friction_area  || 'No capturada'));
lines.push("- Temperatura: "      + state.temperature);
if (state.signals && state.signals.length > 0) {
  lines.push("- Senales: " + state.signals.join(', '));
}
if (state.main_customer_questions && state.main_customer_questions.length > 0) {
  lines.push("- Preguntas del cliente: " + state.main_customer_questions.join(', '));
}
if (state.summary) lines.push("- Resumen: " + state.summary);

const stateText = lines.join('\n');

// === PENDING FIELD CONTEXT ===
const pendingText = state.pending_field
  ? (
      "CAMPO PENDIENTE: \"" + state.pending_field + "\"\n" +
      "PREGUNTA HECHA: \"" + (state.pending_question || 'N/A') + "\"\n" +
      "El usuario probablemente esta respondiendo esta pregunta ahora. " +
      "Captura el valor y limpia pending_field a null."
    )
  : "Sin campo pendiente.";

// === SLOT SELECTION CONTEXT ===
const isWaitingForSlot = (
  Array.isArray(state.available_slots) &&
  state.available_slots.length > 0 &&
  state.next_action === 'book_call'
);

const slotContext = isWaitingForSlot
  ? (
      "=== SELECCION DE HORARIO ===\n" +
      "El usuario esta eligiendo un horario de los que se le presentaron.\n" +
      "Opciones disponibles:\n" +
      state.available_slots.map(function(s, i) {
        return (i + 1) + ") " + s;
      }).join("\n") + "\n\n" +
      "INSTRUCCIONES:\n" +
      "- Si el usuario responde 1, 2 o 3 → confirma el horario elegido, " +
      "establece selected_slot_index = numero elegido, next_action = 'confirm_booking'.\n" +
      "- Si el usuario pide otro dia u horario → next_action = 'reschedule'.\n" +
      "- Si el usuario cancela o no quiere → next_action = 'close'.\n" +
      "- No preguntes nada mas. Solo confirma la seleccion y responde con el horario en lenguaje natural."
    )
  : "";

// === ASSEMBLE PROMPT ===
const ai_prompt =
  "=== HISTORIAL DE CONVERSACION ===\n" +
  historyText + "\n\n" +
  "=== NUEVO MENSAJE DEL USUARIO ===\n" +
  waba.message + "\n\n" +
  "=== LO QUE SABEMOS DEL LEAD ===\n" +
  stateText + "\n\n" +
  "=== CONTEXTO DE TURNO ANTERIOR ===\n" +
  pendingText + "\n\n" +
  (slotContext ? slotContext + "\n\n" : "") +
  "=== ESTADO ACTUAL DEL FLUJO ===\n" +
  "- Accion previa: " + state.next_action + "\n" +
  "- Temperatura: "   + state.temperature;

console.log(
  "Context ready | " + state.phone_number +
  " | next_action: " + state.next_action +
  " | history: " + recentHistory.length + " msgs" +
  " | slots: " + state.available_slots.length +
  " | pending: " + (state.pending_field || 'none') +
  " | source: webchat"
);

// === RETURN ===
return [{
  json: {
    ...row,
    session_id:          row.session_id    || waba.session_id,
    phone_number:        row.phone_number  || waba.phone_number,
    email:               row.email         || waba.email || null,
    latest_user_message: waba.message,
    webhook_name:        waba.name         || null,
    source:              "webchat",
    state:               state,
    history:             history,
    ai_prompt:           ai_prompt
  }
}];

// Node: "State Manager" — Mode: Run Once for All Items
// Purpose: Merge AI output with existing session state and build updated history

const ai   = $input.first().json.output || $input.first().json;
const waba = $('Normalize Web Payload').first().json;
// === GET EXISTING SESSION ===
let row = {};
try {
  const lookup = $('Lookup Lead Session').first().json;
  if (lookup && lookup.session_id) row = lookup;
} catch(e) {}
try {
  if (!row.session_id) {
    const created = $('Create Lead Session').first().json;
    if (created && created.session_id) row = created;
  }
} catch(e) {}

// === REBUILD CONVERSATION HISTORY ===
let history = [];
try {
  let raw = row.conversation_history;
  if (typeof raw === 'string') raw = JSON.parse(raw);
  if (raw && typeof raw === 'object' && !Array.isArray(raw)) {
    raw = raw.data || raw.value || [];
  }
  if (Array.isArray(raw)) history = raw;
} catch(e) {
  history = [];
}

// Append this turn
history.push({ role: "user",      content: waba.message });
history.push({ role: "assistant", content: ai.reply_to_user });

// Cap at 40 messages (20 exchanges)
if (history.length > 40) history = history.slice(-40);

// === RESOLVE SELECTED SLOT ===
// If AI returned a slot index, resolve the actual ISO datetime from available_slots
const availableSlots = Array.isArray(row.available_slots) ? row.available_slots : [];
const aiSlotIndex    = (ai.selected_slot_index != null && ai.selected_slot_index !== undefined)
  ? Number(ai.selected_slot_index)
  : null;

const resolvedSlotIndex = aiSlotIndex ?? row.selected_slot_index ?? null;
const resolvedSlot      = (aiSlotIndex != null && availableSlots.length > 0)
  ? (availableSlots[aiSlotIndex - 1] || null)   // user picks 1-based, array is 0-based
  : (row.selected_slot || null);

// === MERGE STATE ===
// Rule: only overwrite existing DB value if AI captured something new
const merged = {
  session_id:              row.session_id,
  phone_number:            row.phone_number               || waba.phone_number,

  // Identity
  name:                    ai.name                        || row.name            || waba.name || null,
  email:                   ai.email                       || row.email           || null,

  // eCommerce profile
  platform:                ai.platform                    || row.platform        || null,
  communication_channels:  ai.channels && ai.channels.length > 0
                             ? ai.channels
                             : (row.communication_channels || []),
  friction_area:           ai.friction_area               || row.friction_area   || null,
  main_customer_questions: ai.main_customer_questions && ai.main_customer_questions.length > 0
                             ? ai.main_customer_questions
                             : (row.main_customer_questions || []),
  message_volume:          ai.message_volume              || row.message_volume  || null,

  // Decision layer
  signals:                 ai.signals && ai.signals.length > 0
                             ? ai.signals
                             : (row.signals || []),
  temperature:             ai.temperature                 || row.temperature     || "cold",
  next_action:             ai.next_action                 || row.next_action     || "continue",
  summary:                 ai.summary                     || row.summary         || null,

  // Pending turn tracking (always use AI's latest values)
  pending_field:           ai.pending_field               ?? null,
  pending_question:        ai.pending_question            ?? null,

  // Validation flags (never downgrade) — email_valid wired in Phase 2
  email_valid:             row.email_valid                || false,
  phone_valid:             row.phone_valid                || false,
  contact_valid:           row.contact_valid              || false,

  // Conversation memory
  conversation_history:    history,

  // Latest turn
  latest_user_message:     waba.message,
  latest_ai_response:      ai.reply_to_user,

  // Booking
  available_slots:         availableSlots,
  selected_slot:           resolvedSlot,
  selected_slot_index:     resolvedSlotIndex,
  booking_confirmed_at:    row.booking_confirmed_at       || null,

  // CRM
  ghl_contact_id:          row.ghl_contact_id             || null,

  // Location (preserve existing)
  country:                 row.country                    || null,
  country_iso:             row.country_iso                || null,
  country_code:            row.country_code               || null
};

console.log(
  "State merged | " + merged.session_id +
  " | temp: "        + merged.temperature +
  " | next: "        + merged.next_action +
  " | signals: "     + (merged.signals || []).length +
  " | pending: "     + (merged.pending_field || 'none') +
  " | history: "     + history.length + " msgs" +
  " | slot_index: "  + (merged.selected_slot_index || 'none') +
  " | slot: "        + (merged.selected_slot || 'none')
);

return [{ json: merged }];

// Node: "Normalize Web Payload" — Mode: Run Once for All Items
// Purpose: Extract clean fields from web chat webhook payload

const body = $input.first().json.body || $input.first().json;

const session_id   = body.session_id  || null;
const message      = body.message     || "";
const name         = body.name        || null;
const email        = body.email       || null;
const phone_number = body.phone       || "webchat_" + (session_id || "unknown");

if (!session_id) {
  throw new Error("session_id is required from web chat widget");
}

if (!message) {
  throw new Error("message is required");
}

console.log("Web chat | session: " + session_id + " | message: " + message.substring(0, 50));

return [{
  json: {
    session_id:    session_id,
    phone_number:  phone_number,
    message:       message,
    name:          name,
    email:         email,
    message_lower: message.toLowerCase().trim(),
    source:        "webchat"
  }
}];

const data = $json;

// Build transcript
let transcript = '';
if (Array.isArray(data.conversation_history)) {
  transcript = data.conversation_history
    .map(msg => {
      const role = msg.role === 'user' ? 'Usuario' : 'Andrea';
      return role + ': ' + (msg.content || '');
    })
    .join('\n');
}

const payload = {
  contact_info: {
    name: data.name || 'Visitor',
    email: data.email || 'contact@example.com',
    phone: data.phone_number || 'webchat'
  },
  ai_insights: {
    platform: data.platform ? String(data.platform) : '',  // Convert to string, empty if null
    friction_area: data.friction_area ? String(data.friction_area) : '',  // Convert to string
    communication_channels: Array.isArray(data.communication_channels) 
      ? data.communication_channels.join(', ')  // Convert array to comma-separated string
      : (data.communication_channels ? String(data.communication_channels) : ''),
    signals: Array.isArray(data.signals) 
      ? data.signals.join(', ')  // Convert array to comma-separated string
      : (data.signals ? String(data.signals) : ''),
    temperature: data.temperature ? String(data.temperature) : 'cold',
    ai_summary: data.summary ? String(data.summary) : '',
    qualified: (data.temperature === 'hot' || data.temperature === 'warm') ? true : false
  },
  conversation_transcript: transcript || '',
  source: 'webchat'
};

return [{ json: payload }];

const crmResponse = $json;  // This is CRM UPDATE response (has contact_id)
const contact_id = crmResponse.contact_id;
const data = $('Build CRM payload').first().json;  // Get the payload with name, platform, etc.

const payload = { contact_id };

if (data.contact_info.name && data.contact_info.name !== 'Visitor') {
  const parts = data.contact_info.name.trim().split(' ');
  payload.first_name = parts[0];
  payload.last_name = parts.slice(1).join(' ') || 'User';
}

if (data.contact_info.email && data.contact_info.email.includes('@') && data.contact_info.email !== 'contact@example.com') {
  payload.email = data.contact_info.email;
}

if (data.ai_insights.platform) payload.platform = data.ai_insights.platform;
if (data.ai_insights.friction_area) payload.friction_area = data.ai_insights.friction_area;
if (data.ai_insights.communication_channels) payload.communication_channels = data.ai_insights.communication_channels;
if (data.ai_insights.signals) payload.signals = data.ai_insights.signals;
if (data.ai_insights.ai_summary) payload.ai_summary = data.ai_insights.ai_summary;

if (contact_id && Object.keys(payload).length > 1) {
  return [{ json: payload }];
} else {
  return [{ json: { skip_update: true } }];
}
